#include<bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
struct Edge {
	int num, number;
} a[400010];
int n, tree[400010];
int ans, in = 1;
bool operator < (const Edge& x, const Edge& y) {
	return (x.num == y.num) ? x.number < y.number : x.num < y.num;
}
int lowbit (int x) {
	return x & (-x);
}
void update (int i ,int c) {
	for (; i <= n; i += lowbit (i)) {
		tree[i] += c;
	}
}
int getsum (int i) {
	int res = 0;
	for (; i; i -= lowbit (i)) {
		res += tree[i];
	}
	return res;
}
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i].num;
		a[i].number = i;
		update (a[i].number, 1);
	}
	sort (a + 1, a + 1 + n);
	for (int i = 0; i < n; i++) {
		cout << ans << '\n';
		int t = in;
		while (i == a[t].num) {
			ans += getsum (a[t].number - 1);
			update (a[t].number, -1);
			t++;
		}
		in = t;
	}
	return 0;
}
